// src/components/common/DocumentList.js
import React, { useState, useEffect, useCallback } from 'react';
import api from '../../services/api';
import { useToast } from '../../context/ToastContext';
import './DocumentList.css';

const DocumentList = ({ patientId, refreshTrigger }) => {
    const [documents, setDocuments] = useState([]);
    const [loading, setLoading] = useState(true);
    const { showError, showSuccess } = useToast();

    const fetchDocuments = useCallback(async () => {
        if (!patientId) {
            setLoading(false);
            return;
        }
        
        setLoading(true);
        try {
            console.log('Fetching documents for patient:', patientId);
            
            // Get all health records
            const response = await api.get('/health-records');
            console.log('All health records:', response.data);
            
            // Filter records for this patient and extract attachments
            const patientRecords = response.data.filter(record => record.user_id === patientId);
            console.log('Patient records:', patientRecords);
            
            // Extract attachments from records
            const allAttachments = [];
            patientRecords.forEach(record => {
                // Check if record has attachments property and it's an array
                if (record.attachments && Array.isArray(record.attachments)) {
                    allAttachments.push(...record.attachments);
                }
                
                // Also check if there are any attachment fields directly on the record
                if (record.file_name && record.file_path) {
                    allAttachments.push({
                        id: record.id,
                        file_name: record.file_name,
                        file_type: record.file_type,
                        file_size: record.file_size,
                        file_path: record.file_path,
                        description: record.description,
                        uploaded_at: record.created_at
                    });
                }
            });
            
            console.log('Extracted attachments:', allAttachments);
            setDocuments(allAttachments);
        } catch (error) {
            console.error('Error fetching documents:', error);
            showError('Failed to load documents');
        } finally {
            setLoading(false);
        }
    }, [patientId, showError]);

    useEffect(() => {
        fetchDocuments();
    }, [fetchDocuments, refreshTrigger]); // Add refreshTrigger to dependency

    const handleDownload = async (attachmentId, fileName) => {
        try {
            const response = await api.get(`/health-records/attachments/${attachmentId}/download`, {
                responseType: 'blob'
            });
            
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', fileName);
            document.body.appendChild(link);
            link.click();
            link.remove();
            window.URL.revokeObjectURL(url);
            showSuccess('Download started');
        } catch (error) {
            console.error('Download error:', error);
            showError('Failed to download document');
        }
    };

    const handleDelete = async (attachmentId) => {
        if (window.confirm('Are you sure you want to delete this document?')) {
            try {
                await api.delete(`/health-records/attachments/${attachmentId}`);
                showSuccess('Document deleted successfully');
                fetchDocuments(); // Refresh the list
            } catch (error) {
                console.error('Delete error:', error);
                showError('Failed to delete document');
            }
        }
    };

    const getFileIcon = (fileType) => {
        if (!fileType) return '📎';
        if (fileType.includes('pdf')) return '📄';
        if (fileType.includes('image')) return '🖼️';
        if (fileType.includes('word')) return '📝';
        if (fileType.includes('text')) return '📃';
        return '📎';
    };

    const formatFileSize = (bytes) => {
        if (!bytes) return 'Unknown';
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / (1024 * 1024)).toFixed(2) + ' MB';
    };

    const formatDate = (dateString) => {
        if (!dateString) return 'Unknown date';
        return new Date(dateString).toLocaleDateString();
    };

    if (loading) return <div className="loading-docs">Loading documents...</div>;

    return (
        <div className="document-list">
            <h4>Patient Documents ({documents.length})</h4>
            {documents.length === 0 ? (
                <div className="no-documents">
                    <p>No documents uploaded yet</p>
                    <p className="hint">Upload medical reports, prescriptions, or images above</p>
                </div>
            ) : (
                <div className="documents-grid">
                    {documents.map((doc, index) => (
                        <div key={doc.id || index} className="document-card">
                            <div className="document-icon">
                                {getFileIcon(doc.file_type)}
                            </div>
                            <div className="document-info">
                                <div className="document-name">{doc.file_name || 'Untitled'}</div>
                                <div className="document-meta">
                                    <span className="document-date">
                                        📅 {formatDate(doc.uploaded_at || doc.created_at)}
                                    </span>
                                    <span className="document-size">
                                        💾 {formatFileSize(doc.file_size)}
                                    </span>
                                </div>
                                {doc.description && (
                                    <div className="document-description">📝 {doc.description}</div>
                                )}
                            </div>
                            <div className="document-actions">
                                <button 
                                    onClick={() => handleDownload(doc.id, doc.file_name)}
                                    className="download-button"
                                    title="Download"
                                >
                                    📥
                                </button>
                                <button 
                                    onClick={() => handleDelete(doc.id)}
                                    className="delete-button"
                                    title="Delete"
                                >
                                    🗑️
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default DocumentList;
